import org.eclipse.rdf4j.sail.lmdb.sketch.SketchStatementSource;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbQuadSynopsisServiceTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P = VF.createIRI("urn:predicate");

	@TempDir
	Path directory;

	@Test
	void rebuildDeltaDeletionAndRestartUseOneLifecycle() {
		MutableStatementSource source = new MutableStatementSource();
		Statement first = VF.createStatement(VF.createIRI("urn:s1"), P, VF.createLiteral(1));
		Statement second = VF.createStatement(VF.createIRI("urn:s2"), P, VF.createLiteral(2));
		source.statements.addAll(List.of(first, second));
		LmdbQuadSynopsisService service = service(source);
		service.configurePersistence(directory, false);
		service.requestRebuild();

		assertTrue(service.forceFlush());
		assertEquals(2.0d, predicateRows(service));

		Statement third = VF.createStatement(VF.createIRI("urn:s3"), P, VF.createLiteral(3));
		source.statements.add(third);
		service.addStatement(third);
		assertEquals(3.0d, predicateRows(service));

		source.statements.remove(first);
		service.deleteStatement(first);
		assertFalse(service.isReadyNonBlocking());
		assertTrue(service.forceFlush());
		assertEquals(2.0d, predicateRows(service));
		service.persistIfDirty();
		service.close();

		LmdbQuadSynopsisService restarted = service(source);
		restarted.configurePersistence(directory, true);
		assertTrue(restarted.isReadyNonBlocking());
		assertEquals(2.0d, predicateRows(restarted));
		restarted.close();
	}

	@Test
	void concurrentPersistencePublishesOneReadableSnapshot() throws Exception {
		MutableStatementSource source = new MutableStatementSource();
		for (int index = 0; index < 100; index++) {
			source.statements.add(VF.createStatement(VF.createIRI("urn:concurrent:s" + index), P,
					VF.createLiteral(index)));
		}
		LmdbQuadSynopsisService service = service(source);
		service.configurePersistence(directory, false);
		service.requestRebuild();
		assertTrue(service.forceFlush());

		int writers = 4;
		CountDownLatch ready = new CountDownLatch(writers);
		CountDownLatch start = new CountDownLatch(1);
		ExecutorService executor = Executors.newFixedThreadPool(writers);
		try {
			List<Future<?>> futures = new ArrayList<>();
			for (int index = 0; index < writers; index++) {
				futures.add(executor.submit(() -> {
					ready.countDown();
					start.await();
					service.persistIfDirty();
					return null;
				}));
			}
			ready.await();
			start.countDown();
			for (Future<?> future : futures) {
				future.get();
			}
		} finally {
			executor.shutdownNow();
		}

		QuadSynopsisLoadResult result = QuadSynopsisPersistence.read(directory.resolve("synopsis-v8.bin"),
				QuadSynopsisBudget.create(4L * 1024L * 1024L, 128));
		assertFalse(result.rebuildRequired());
		assertEquals(100L, result.snapshot().orElseThrow().totalRows());
		service.close();
	}

	@Test
	void batchAdditionsAndDeferredSizeDeltasShareOneLifecycle() {
		MutableStatementSource source = new MutableStatementSource();
		LmdbQuadSynopsisService service = service(source);
		service.requestRebuild();
		assertTrue(service.forceFlush());

		List<Statement> additions = List.of(
				VF.createStatement(VF.createIRI("urn:batch:s1"), P, VF.createLiteral(1)),
				VF.createStatement(VF.createIRI("urn:batch:s2"), P, VF.createLiteral(2)),
				VF.createStatement(VF.createIRI("urn:batch:s3"), P, VF.createLiteral(3)));
		source.statements.addAll(additions);
		service.addStatements(additions);
		assertEquals(3.0d, predicateRows(service));
		assertTrue(service.isReadyNonBlocking());

		Statement deferred = VF.createStatement(VF.createIRI("urn:batch:s4"), P, VF.createLiteral(4));
		source.statements.add(deferred);
		service.recordStoreSizeDelta(1L, 0L);
		assertFalse(service.isReadyNonBlocking());
		assertTrue(service.forceFlush());
		assertEquals(4.0d, predicateRows(service));
		service.close();
	}

	private static LmdbQuadSynopsisService service(SketchStatementSource source) {
		return new LmdbQuadSynopsisService(source, 4L * 1024L * 1024L, 128, Long.MAX_VALUE, 0L);
	}

	private static double predicateRows(LmdbQuadSynopsisService service) {
		QuadProbe probe = new QuadProbe(QuadProbe.PREDICATE, QuadProbe.OBJECT, 0L, QuadValueHash.hash(P), 0L, 0L,
				service.snapshotIdentity());
		return service.probe(probe).rows().estimate();
	}

	private static final class MutableStatementSource implements SketchStatementSource {
		private final List<Statement> statements = new ArrayList<>();

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subject, IRI predicate, Value object,
				Resource... contexts) {
			return new CloseableIteratorIteration<>(statements.iterator());
		}
	}
}
